template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create the table if it doesn't exist
  auto create_table_result = (sqlgen::create_table<T> | sqlgen::if_not_exists)(conn);
  if (!create_table_result) {
    throw std::runtime_error("Failed to create table");
  }

  // Insert the records
  auto insert_result = sqlgen::insert(conn, records);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {
  // Determine the table type based on table name
  if (table_name == "Student") {
    // Delete from Student table using SNo as primary key
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
      throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    auto delete_result = (sqlgen::delete_from<Student> | sqlgen::where("SNo"_c == record_id))(conn);
    if (!delete_result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Course") {
    // Delete from Course table using CID as primary key
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
      throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    auto delete_result = (sqlgen::delete_from<Course> | sqlgen::where("CID"_c == record_id))(conn);
    if (!delete_result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Score") {
    // Delete from Score table using ScID as primary key
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
      throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    auto delete_result = (sqlgen::delete_from<Score> | sqlgen::where("ScID"_c == record_id))(conn);
    if (!delete_result) {
      throw std::runtime_error("Failed to delete record");
    }
  } else if (table_name == "Major") {
    // Delete from Major table using MID as primary key
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
      throw std::runtime_error("Failed to connect to database");
