    // Start with base SELECT query
    auto query = sqlgen::select_from<Book>("book_id"_c, "title"_c, "author"_c, "year"_c, "genre"_c, "price"_c);

    // Dynamically add WHERE clauses based on non-null filters
    auto condition = 1 == 1; // Always true to start

    if (filters.title_keyword) {
