#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Start transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  // Read from_account to check balance
  auto from_account_result = conn->read<Account>(sqlgen::where("account_id"_c == from_account_id));
  if (!from_account_result) {
    conn->rollback();
    return false;
  }

  auto from_account = from_account_result.value();

  // Verify sufficient funds
  if (from_account.balance < amount) {
    conn->rollback();
    return false;
  }

  // Update from_account: balance = balance - amount with verification
  auto update_from_stmt = sqlgen::update<Account>("balance"_c.set("balance"_c - amount))
                         | sqlgen::where("account_id"_c == from_account_id && "balance"_c >= amount);

  auto update_from_result = update_from_stmt(conn);
  if (!update_from_result) {
    conn->rollback();
    return false;
  }

  // Update to_account: balance = balance + amount
  auto update_to_stmt = sqlgen::update<Account>("balance"_c.set("balance"_c + amount))
                       | sqlgen::where("account_id"_c == to_account_id);

  auto update_to_result = update_to_stmt(conn);
  if (!update_to_result) {
    conn->rollback();
    return false;
  }

  // Commit transaction
  auto commit_result = conn->commit();
  if (!commit_result) {
    conn->rollback();
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
