#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Return error code on connection failure
  }
  auto conn = *conn_result;

  // First update: expire pending orders older than 7 days
  auto update1 = sqlgen::update<Order>("status"_c.set("expired"))
                | sqlgen::where("status"_c == "pending" && 
                               "order_date"_c < "DATE('now', '-7 days')");

  // Second update: mark shipped orders as delivered
  auto update2 = sqlgen::update<Order>("status"_c.set("delivered"))
                | sqlgen::where("status"_c == "shipped");

  // Execute both updates and get affected rows
  auto result1 = conn->execute(conn->to_sql(update1));
  auto result2 = conn->execute(conn->to_sql(update2));

  if (!result1 || !result2) {
    return -1; // Return error code on execution failure
  }

  // Calculate total affected rows
  int affected_rows = conn->changes();

  return affected_rows;
}

} // namespace update_order_status
```

