namespace join_orders_customers_payments {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct Payment {
  sqlgen::PrimaryKey<int> payment_id;
  int order_id;
  double amount;
};

struct Consolidated {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer_name;
  double amount;
};

/**
 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using sqlgen::select_from with Order table and appropriate aliases
  auto query = sqlgen::select_from<Order, "o">(
    "order_id"_o | sqlgen::as<"order_id">,
    "name"_c | sqlgen::as<"customer_name">,
    "amount"_p | sqlgen::as<"amount">
  )
  // Chain inner joins using the | operator with sqlgen::inner_join
  | sqlgen::inner_join<Customer, "c">("customer_id"_o == "customer_id"_c)
  | sqlgen::inner_join<Payment, "p">("order_id"_o == "order_id"_p)
  // Apply order_by with descending order on the amount column
  | sqlgen::order_by("amount"_p.desc());

  // Execute the query and return the results
  return query(conn).value();
}

}  // namespace join_orders_customers_payments
